export type WorkspaceTabKind = 'report' | 'document';

export type WorkspaceTab = {
  id: string;
  path: string;
  title: string;
  tabKind: WorkspaceTabKind;
  /** Drill-down document type — used to replace tab when opening same type. */
  documentType?: string;
};

export type OpenWorkspaceTabInput = {
  path: string;
  title: string;
  /** When true (default), switch if a tab with the same path already exists. */
  reuseExisting?: boolean;
  /** Report URL to anchor as first tab and restore when all document tabs close. */
  returnPath?: string;
  /** Title for report anchor tab (default: titleFromPath(returnPath)). */
  returnTitle?: string;
  /** e.g. CashReceipt — one workspace tab per type; new open replaces path/title. */
  documentType?: string;
};

declare global {
  interface Window {
    __LINM_OPEN_WORKSPACE_TAB__?: (input: OpenWorkspaceTabInput) => void;
    __LINM_SHELL_WORKSPACE_TABS__?: boolean;
  }
}

export function titleFromPath(path: string): string {
  const base = path.split('?')[0];
  const segments = base.split('/').filter(Boolean);
  const last = segments[segments.length - 1] ?? 'Trang';
  if (/^[0-9a-f-]{36}$/i.test(last) && segments.length >= 2) {
    const parent = segments[segments.length - 2];
    const map: Record<string, string> = {
      pt: 'Phiếu thu',
      pc: 'Phiếu chi',
      pdc: 'Phiếu ĐC',
      pkt: 'Bút toán',
      pnm: 'PNM',
      'pnm-xt': 'PNM XT',
      'hdmh-dv': 'HĐ mua DV',
      'tam-ung': 'Tạm ứng',
      'so-cai': 'Sổ cái',
      'so-chi-tiet': 'Sổ chi tiết',
    };
    return map[parent] ?? parent;
  }
  const map: Record<string, string> = {
    'so-cai': 'Sổ cái',
    'so-chi-tiet': 'Sổ chi tiết',
    'so-tong-hop': 'Sổ tổng hợp',
    'cong-no': 'Công nợ',
    cdps: 'CDPS',
    pt: 'Phiếu thu',
    pc: 'Phiếu chi',
  };
  return map[last] ?? last;
}
