import React from 'react';
import { Link, Outlet, useLocation, useNavigate } from 'react-router-dom';
import { DevCompanyPicker, ReduxToastContainer, useResponsive } from '@linm-soft/common-components';
import '@linm-soft/common-components/styles/variables.css';
import { isStandalone, showDevNav } from '../../../dev/isStandalone';
import { useListFilterSessionGuard } from '../../../hooks/useListFilterSessionGuard';
import { isVoucherFormPath } from '../../../utils/isVoucherFormPath';
import { WorkspaceTabBar, WorkspaceTabProvider } from '../../../workspace';
import styles from './AppLayout.module.css';
import '../../../styles/reportPrint.css';

const getPageTitle = (pathname: string): string => {
  if (pathname.startsWith('/dev')) return 'Dev Navigation';
  if (pathname.startsWith('/kt')) return 'Kế Toán';
  if (pathname.startsWith('/gt')) return 'Giá Thành';
  if (pathname.startsWith('/tscd')) return 'Tài Sản Cố Định';
  return 'ERP Tài Chính';
};

function isShellWorkspaceTabHost(): boolean {
  return typeof window !== 'undefined' && window.__LINM_SHELL_WORKSPACE_TABS__ === true;
}

export const AppLayout: React.FC = () => {
  useListFilterSessionGuard();
  const navigate = useNavigate();
  const location = useLocation();
  const { isMobile } = useResponsive();
  const title = getPageTitle(location.pathname);
  const voucherFormShell = isVoucherFormPath(location.pathname);
  const shellWorkspaceTabs = isShellWorkspaceTabHost();

  const layoutBody = (
    <div
      className={[
        styles.main,
        isStandalone ? styles.mainStandalone : styles.mainEmbedded,
      ].filter(Boolean).join(' ')}
      data-modal-root
    >
      {isStandalone && (
        <header className={styles.topbar}>
          <div className={styles.topbarLeft}>
            {isMobile && (
              <button
                type="button"
                className={styles.menuButton}
                onClick={() => window.dispatchEvent(new CustomEvent('linm:nav:toggle-mobile'))}
                aria-label="Mở menu"
              >
                <i className="fas fa-bars" />
              </button>
            )}
            <h1 className={styles.title}>{title}</h1>
          </div>
          {showDevNav && !location.pathname.startsWith('/dev') && (
            <Link to="/dev" className={styles.devLink} title="Dev Navigation">
              <i className="fas fa-wrench" aria-hidden />
            </Link>
          )}
        </header>
      )}
      {isStandalone && showDevNav && !location.pathname.startsWith('/dev') && (
        <div className={styles.devCompanyBar}>
          <DevCompanyPicker />
        </div>
      )}
      {!shellWorkspaceTabs ? <WorkspaceTabBar /> : null}
      <div
        className={[
          styles.content,
          voucherFormShell ? styles.contentVoucherShell : '',
        ].filter(Boolean).join(' ')}
      >
        <Outlet />
      </div>
      {isStandalone && <ReduxToastContainer />}
    </div>
  );

  if (shellWorkspaceTabs) {
    return layoutBody;
  }

  return (
    <WorkspaceTabProvider navigate={navigate}>
      {layoutBody}
    </WorkspaceTabProvider>
  );
};

export default AppLayout;
